"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[849],{6164(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"defaultSidebar":[{"type":"link","href":"/docs/introduction","label":"Introduction","docId":"introduction","unlisted":false},{"type":"category","label":"Getting Started","items":[{"type":"link","href":"/docs/examples","label":"Hands-On Examples","docId":"examples","unlisted":false},{"type":"link","href":"/docs/onnx","label":"ONNX Inference","docId":"onnx","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Architecture","items":[{"type":"link","href":"/docs/architecture/pipeline","label":"Execution Pipeline","docId":"architecture/pipeline","unlisted":false},{"type":"link","href":"/docs/architecture/jit-loader","label":"JIT Compiler","docId":"architecture/jit-loader","unlisted":false},{"type":"category","label":"Codegen Pipeline","items":[{"type":"link","href":"/docs/architecture/codegen/overview","label":"Overview","docId":"architecture/codegen/overview","unlisted":false},{"type":"link","href":"/docs/architecture/codegen/rangeify","label":"Phase 1 \u2014 Rangeify","docId":"architecture/codegen/rangeify","unlisted":false},{"type":"link","href":"/docs/architecture/codegen/expander","label":"Phase 2 \u2014 Expander","docId":"architecture/codegen/expander","unlisted":false},{"type":"link","href":"/docs/architecture/codegen/devectorizer","label":"Phase 3 \u2014 Devectorizer","docId":"architecture/codegen/devectorizer","unlisted":false},{"type":"link","href":"/docs/architecture/codegen/linearizer","label":"Phase 4 \u2014 Linearizer","docId":"architecture/codegen/linearizer","unlisted":false},{"type":"link","href":"/docs/architecture/codegen/worked-example","label":"Worked Example & Reference","docId":"architecture/codegen/worked-example","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","href":"/docs/architecture/ir-design","label":"IR Design Philosophy","docId":"architecture/ir-design","unlisted":false},{"type":"category","label":"Optimizations","items":[{"type":"link","href":"/docs/architecture/optimizations/pattern-system","label":"Pattern Engine","docId":"architecture/optimizations/pattern-system","unlisted":false},{"type":"link","href":"/docs/architecture/optimizations/algebraic-simplification","label":"Algebraic Simplification","docId":"architecture/optimizations/algebraic-simplification","unlisted":false},{"type":"link","href":"/docs/architecture/optimizations/index-arithmetic","label":"Index Arithmetic","docId":"architecture/optimizations/index-arithmetic","unlisted":false},{"type":"link","href":"/docs/architecture/optimizations/range-optimization","label":"Range & Reduce","docId":"architecture/optimizations/range-optimization","unlisted":false},{"type":"link","href":"/docs/architecture/optimizations/strength-reduction","label":"Strength Reduction","docId":"architecture/optimizations/strength-reduction","unlisted":false},{"type":"link","href":"/docs/architecture/optimizations/kernel-search","label":"Kernel Search","docId":"architecture/optimizations/kernel-search","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","href":"/docs/architecture/op-bestiary","label":"Op Bestiary","docId":"architecture/op-bestiary","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"architecture/codegen/devectorizer":{"id":"architecture/codegen/devectorizer","title":"Phase 3: Devectorizer","description":"Goal: Lower from hardware-agnostic vectors to hardware-specific instructions.","sidebar":"defaultSidebar"},"architecture/codegen/expander":{"id":"architecture/codegen/expander","title":"Phase 2: Expander","description":"Goal: Transform optimization primitives (UNROLL/UPCAST) into explicit operations.","sidebar":"defaultSidebar"},"architecture/codegen/linearizer":{"id":"architecture/codegen/linearizer","title":"Phase 4: Linearizer","description":"Goal: Convert the DAG to a linear instruction sequence.","sidebar":"defaultSidebar"},"architecture/codegen/overview":{"id":"architecture/codegen/overview","title":"Path of the UOp: The 22-Stage Codegen Pipeline","description":"A UOp starts as a high-level tensor expression. By the time it reaches the hardware, it has been transformed through 22 distinct stages\u2014each with a specific purpose, each building on the last. This chapter traces that journey.","sidebar":"defaultSidebar"},"architecture/codegen/rangeify":{"id":"architecture/codegen/rangeify","title":"Phase 1: Rangeify","description":"Goal: Transform high-level movement operations into explicit loop structures and optimize ranges.","sidebar":"defaultSidebar"},"architecture/codegen/worked-example":{"id":"architecture/codegen/worked-example","title":"Worked Example & Reference","description":"---","sidebar":"defaultSidebar"},"architecture/ir-design":{"id":"architecture/ir-design","title":"One IR to Rule Them All","description":"You\'re debugging a slow model. The profiler says \\"kernel X takes 200ms\\" but you have no idea what kernel X actually does. You trace through PyTorch\'s dispatcher, then ATen, then TorchInductor, then Triton IR, and finally land in LLVM IR. Five different representations, five different mental models, five different debugging tools.","sidebar":"defaultSidebar"},"architecture/jit-loader":{"id":"architecture/jit-loader","title":"JIT Compiler","description":"Most ML compilers either link an entire LLVM toolchain into the binary \u2014 adding hundreds of megabytes of dependencies \u2014 or write temporary files to disk and dlopen the result. Morok does neither.","sidebar":"defaultSidebar"},"architecture/op-bestiary":{"id":"architecture/op-bestiary","title":"Op Bestiary: A Field Guide to UOp Operations","description":"When debugging Morok IR dumps, you\'ll encounter operations that aren\'t obvious from their names. This chapter documents non-trivial operations with signatures, field explanations, and examples.","sidebar":"defaultSidebar"},"architecture/optimizations/algebraic-simplification":{"id":"architecture/optimizations/algebraic-simplification","title":"Algebraic Simplification Patterns","description":"Morok\'s symbolic simplifier rewrites UOp computation graphs using 140+ algebraic patterns defined in schedule/src/symbolic/patterns.rs. These patterns fire at multiple points in the pipeline:","sidebar":"defaultSidebar"},"architecture/optimizations/index-arithmetic":{"id":"architecture/optimizations/index-arithmetic","title":"Index Arithmetic","description":"Tensor compilers spend most of their optimization budget on index arithmetic. A tensor[i, j] access with shape [H, W] becomes i * W + j. After tiling, vectorization, and loop transformations, these expressions accumulate nested divisions and modulos. Simplifying them is critical \u2014 a single unnecessary idiv costs 20-40 cycles vs 1 cycle for the equivalent shift (approximate, modern x86-64).","sidebar":"defaultSidebar"},"architecture/optimizations/kernel-search":{"id":"architecture/optimizations/kernel-search","title":"Kernel Optimization Search","description":"After algebraic simplification, each kernel needs scheduling decisions fast heuristics and thorough beam search.","sidebar":"defaultSidebar"},"architecture/optimizations/pattern-system":{"id":"architecture/optimizations/pattern-system","title":"The Pattern Engine","description":"Open any production ML compiler and you\'ll find dozens of optimization passes: constant folding, dead code elimination, operator fusion, loop tiling, vectorization, memory layout optimization. Each pass has its own data structures, its own traversal logic, its own bugs.","sidebar":"defaultSidebar"},"architecture/optimizations/range-optimization":{"id":"architecture/optimizations/range-optimization","title":"Range and Reduce Optimization","description":"Loop structures are the primary target for optimization in tensor compilers. A naive element-wise addition of two [1024, 1024] tensors generates a single loop over 1M elements. After optimization, it becomes 1024 parallel threads each processing 1024 elements with vectorized loads/stores. Range optimization is how we get there.","sidebar":"defaultSidebar"},"architecture/optimizations/strength-reduction":{"id":"architecture/optimizations/strength-reduction","title":"Strength Reduction and Late Rewrite Patterns","description":"Strength reduction replaces expensive operations with cheaper equivalents. These patterns run late in the pipeline (Stages 18-19) because earlier passes need to see the original operation structure. For example, Add(Mul(a, b), c) must remain visible for algebraic simplification before being fused into MULACC(a, b, c).","sidebar":"defaultSidebar"},"architecture/pipeline":{"id":"architecture/pipeline","title":"From Tensor to Machine Code","description":"In most ML frameworks, computation happens immediately. Write a + b in PyTorch and it runs now\u2014the GPU crunches numbers before you can even inspect the result. This eager execution is simple to understand, but it leaves optimization opportunities on the table. How can a compiler optimize a computation it hasn\'t seen yet?","sidebar":"defaultSidebar"},"examples":{"id":"examples","title":"Hands-On: From Tensors to Models","description":"This chapter teaches Morok through progressive examples. You\'ll start with basic tensor operations and build up to a working neural network classifier.","sidebar":"defaultSidebar"},"introduction":{"id":"introduction","title":"Morok","description":"\u26a0\ufe0f Pre-alpha software. APIs are unstable and may change without notice. Not recommended for production use. \ud83d\udea7\ud83d\udc80","sidebar":"defaultSidebar"},"onnx":{"id":"onnx","title":"ONNX Model Inference","description":"Morok\'s ONNX importer is the recommended way to run model inference. It loads standard .onnx files, decomposes operators into Morok\'s lazy tensor operations, and compiles them through the full optimization pipeline \u2014 no C++ runtime required.","sidebar":"defaultSidebar"}}}}')}}]);